// ─── AGGREGATE HELPERS ───────────────────────────────────────────────────────

export function trainingCostToLevel(targetLevel: number): { guidebooks: number; certificates: number } {
  return OVERLORD_TRAINING_LEVELS
    .filter(l => l.level <= targetLevel)
    .reduce((sum, l) => ({ guidebooks: sum.guidebooks + l.guidebooks, certificates: sum.certificates + l.certificates }), { guidebooks: 0, certificates: 0 });
}

export function totalTrainingCostToLevel(targetLevel: number): { guidebooks: number; certificates: number } {
  const single = trainingCostToLevel(targetLevel);
  return { guidebooks: single.guidebooks * 3, certificates: single.certificates * 3 };
}

export function skillBadgesToLevel(targetLevel: number): number {
  return OVERLORD_SKILL_LEVELS
    .filter(l => l.level <= targetLevel)
    .reduce((sum, l) => sum + l.badges, 0);
}

export function getOverlordCostSummary(): string {
  const deployAt   = totalTrainingCostToLevel(100);
  const maxLevel   = OVERLORD_TRAINING_META.maxTrainingLevel;
  const maxAll     = totalTrainingCostToLevel(maxLevel);
  const totalBadges = skillBadgesToLevel(OVERLORD_SKILL_LEVELS.length);
  const totalShards = OVERLORD_PROMO_LEVELS.reduce((s, l) => s + l.shards, 0);
  const bondMilestones = OVERLORD_BOND_RATINGS
    .filter(b => b.training_unlock)
    .map(b => `  ${b.name} (tier ${b.tier}): all specs to level ${b.training_unlock}`)
    .join('\n');
  return `=== OVERLORD COST DATA (Powered by cpt-hedge.com) ===

Training to deploy (all 3 specs to level 100):
  Guidebooks:   ${deployAt.guidebooks.toLocaleString()}
  Certificates: ${deployAt.certificates.toLocaleString()}

Training to max (all 3 specs to level ${maxLevel}):
  Guidebooks:   ${maxAll.guidebooks.toLocaleString()}
  Certificates: ${maxAll.certificates.toLocaleString()}

Bond Rating training gates:
${bondMilestones}

Promotion — total Overlord Shards to max: ${totalShards.toLocaleString()}
Skills — total Skill Badges to max: ${totalBadges.toLocaleString()}
Per-level badge cost: ${OVERLORD_SKILL_LEVELS.map(l => `L${l.level}:${l.badges}`).join(' | ')}`;
}
